import React from "react";
import "./home.css";
import Links from './links'
import Typed from 'react-typed';

// import res from './data/resume.pdf'
// import res from 'https://github.com/angelmacwan/angelmacwan.github.io/blob/master/RESUME_ANGEL_MACWAN.pdf'

function Home() {

const tspd=25;
	return (
		<div className='Home'>
			<div className='containerHome neu'>
				<div>

					<h2>
						<Typed
						strings={['&lt; HELLO WORLD / &gt;']}
							typeSpeed={tspd}
							backSpeed={20}			
							showCursor={false}>
						</Typed>
					</h2>

					<h1>
						<Typed
						strings={['I AM ANGLE', 'I AM ANGEL MACWAN']}
							typeSpeed={tspd+5}
							backSpeed={20}
							showCursor={false}
							startDelay={1200} >
						</Typed>
					</h1>



					<h2>
						<Typed
							strings={['DEVELOPER // DESIGNER']}
							typeSpeed={tspd}
							backSpeed={20}
							showCursor={false}
							startDelay={3000} >
						</Typed>
					</h2>


					<h2>
						<Typed
							strings={['How can I help you!']}
							typeSpeed={tspd}
							backSpeed={20}
							showCursor={false}
							startDelay={4000} >
						</Typed>
					</h2>
				</div>
				<div id='pfp'></div>
			</div>

			<Links />

			<a href='https://github.com/angelmacwan/angelmacwan.github.io/raw/master/RESUME_ANGEL_MACWAN.pdf' target='_blank' className='res neubtn'>
				RESUME
			</a>
		</div>
	);
}

export default Home;
